var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mmm...","TWN":"呃嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"깼니?","JPN":"気がついたかしら？","ENG":"Finally awake, I see?","TWN":"醒了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……헤, 헤론 님?!","JPN":"……ヘ、ヘロン様！？","ENG":"M-madam H-Heron?!","TWN":"海……海倫夫人？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아앗.","JPN":"ああっ。","ENG":"Aah...!","TWN":"噢嗚…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어머. 일어나면 안 돼. 아직 어지러울 거야.","JPN":"あら。起きたらダメよ。まだクラクラするでしょうから。","ENG":"Oh, don’t get up. You have a concussion.","TWN":"哎呀，你還不能起來，頭應該還很暈吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"안색이 안 좋아서 수액을 놓은 참이란다. 좀 괜찮니?","JPN":"顔色が悪かったから、今点滴を打ったのよ。大丈夫？","ENG":"You don’t look so good, so we were just about to give you an IV. Are you all right?","TWN":"你臉色不太好，正在幫你打點滴，感覺還好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여기는…….","JPN":"ここは……","ENG":"Where am I…?","TWN":"這裡是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아! 그게 궁금했구나?","JPN":"ああ！　それが気になってたのね。","ENG":"Oh! Is that what you want to know?","TWN":"你好奇嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드야. 네가 쭉 지내왔던 곳.","JPN":"ウィザードよ。あなたがずっと暮らしてきた場所。","ENG":"You’re at Wizard... The place you grew up.","TWN":"這裡是魔法師，就是你長大的地方。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……역시 알고 계셨네요.","JPN":"……やっぱり知ってたんですね。","ENG":"So you did know who I was...","TWN":"……您果然認得我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"으음, 아무래도 오랫동안 보아 왔으니까. 헤이븐 님이 널 점찍어 데려오라고 할 때부터 말이야.","JPN":"そりゃ、長い間見てきたんですもの。ヘイブン様があなたを指名して連れてくるように命じた時からね。","ENG":"Hmm... Well, we’ve seen each other plenty, after Mr. Haven picked you out of the litter.","TWN":"嗯嗯，我也算是看著你長大的，自從天堂先生看中你，讓我把你帶回來開始到現在。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 형님이 저를요?","JPN":"ヘイブン兄貴が、私を？","ENG":"Mr. Haven picked me?","TWN":"天堂大哥看中我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼. 네가 가출하고 떠돌던 때부터 줄곧 널 지켜 보셨단다.","JPN":"そう。あなたが家出してさまよってた頃から、ずっとあなたを見守っていらっしゃったの。","ENG":"Of course. He’s been watching you ever since you were living out on the streets.","TWN":"沒錯，打從你離家出走流浪街頭，他就一直有在注意你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"집으로 돌아갈 낌새가 보이길래 위저드 아이들을 이용해서 널 다치게 만들었고.","JPN":"家に帰りそうだったから、ウィザードの子たちを使ってあなたに怪我させたりもしたわね。","ENG":"Just when we thought you were heading back home, we used our children to hurt you.","TWN":"他看你似乎有打算回家的跡象，於是便派魔法師的孩子打傷你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"뭐…… 라고요?","JPN":"なん……ですって？","ENG":"What... did you just say?","TWN":"什……什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드의 소중한 인력이 될 텐데 그냥 보내줄 순 없잖니?","JPN":"ウィザードの大事な人手になるはずなのに、素直に行かせるわけにはいかないでしょう？","ENG":"We couldn't let a potential Wizard member slip through our fingers, could we?","TWN":"你是魔法師看中的人才，當然不能輕易放你走的嘛。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님은 원하는 게 있으면 수단 방법을 가리지 않으시니까. 참 매정하시기도 하지.","JPN":"ヘイブン様は欲しいものには手段を選ばないのよ。なんて冷たい方なのかしら。","ENG":"Mr. Haven doesn’t take no for an answer. Cruel, isn’t it?","TWN":"天堂先生對於想要的東西，一向是不擇手段的，有點冷酷對吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럴 리가…… 헤이븐 형님이 어떻게…….","JPN":"そんな……ヘイブン兄貴がなんで……","ENG":"There’s no way... How could he do...","TWN":"怎麼會……天堂大哥竟然……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"물론 네가 기대에 못 미치는 아이였다는 걸 알고 금방 싫증내셨지만.","JPN":"もちろん、あなたが期待外れの子だってことを知ってからはすぐ飽きてしまわれたけれど。","ENG":"But, of course, he grew tired of you after you failed to meet his expectations.","TWN":"不過當他知道你無法達到他的期待後，也就立刻對你產生反感。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하지만 난 네가 분명 큰일을 해낼 거라고 믿었어.","JPN":"でも、私はあなたがきっとすごいことをやり遂げると信じていたわ。","ENG":"But I always knew you were destined for greatness.","TWN":"但我知道你一定能成大事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래서 직접 거둬 위저드에서 자라도록 해주었단다.","JPN":"だから直接引き取って、ウィザードで暮らせるようにしてあげたの。","ENG":"That’s why I took you into Wizard myself.","TWN":"所以才會親自收留你，讓你在魔法師裡成長茁壯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그대로 널 헤이븐 님께서 내버려뒀다면, 어떻게 됐을지 모르지.","JPN":"あの時そのままヘイブン様のところに置いておいたら、どうなっていたことやら。","ENG":"If I had left you with Mr. Haven, who knows what might’ve happened to you.","TWN":"要是就這樣把你交給他，不知道會變怎樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"결과적으로는 헤이븐 님의 안목도, 내 선택도 모두 좋은 결과로 이어졌어. 우리 조직이 늘 그래 왔듯.","JPN":"結果的にはヘイブン様の洞察力も、私の選択もすべてよい結果に繋がった。私たちの組織がいつもそうだったようにね。","ENG":"In the end, Mr. Haven's keen eye and my decision to take you in all contributed to a positive outcome. Just like everything else about our organization.","TWN":"就結論而言，天堂先生的眼光和我的決定，最後都有好的結果，我們組織一直以來都是如此。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"글린다.","JPN":"グリンダ。","ENG":"Glinda.","TWN":"格琳達。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네, 네?!","JPN":"は、はい！？","ENG":"Y-yes?!","TWN":"蛤？是？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"참 잘했어. 네가 너무 자랑스러워.","JPN":"よくやったわ。あなたをとても誇らしく思うの。","ENG":"You did well. I’m so proud of you.","TWN":"你做得很好，我以你為榮。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"너와 같이 있던 그 아이 말이야.","JPN":"あなたと一緒にいたあの子のことよ。","ENG":"But about the child that was with you...","TWN":"我是說和你一起的那個孩子，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그 어떤 누구도 붙잡지 못했는데, 네 덕분에 손쉽게 잡았지 뭐니.","JPN":"誰も捕まえられなかったのに、あなたのおかげで簡単に捕まえられたわ。","ENG":"No matter how hard they tried, no one could catch her. But you did it effortlessly.","TWN":"都沒人抓得到她，幸虧有你才能輕易抓到她。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그 아이라면…… 루루?","JPN":"あの子って……ルル？","ENG":"Are you... talking about Lulu?","TWN":"那個孩子……是指露露？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루, 루루는 어떻게 됐어요?!","JPN":"ル、ルルはどうなったんですか！？","ENG":"W-where’s Lulu?!","TWN":"露…露露她怎麼樣了？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어머. 진정하렴. 아직 무사해. 내가 안전한 곳에 데려다 놨거든.","JPN":"まあ。落ち着いて。まだ無事よ。私が安全なところに連れていったから。","ENG":"Oh my, calm down. She’s fine... For the time being, I've placed her somewhere safe.","TWN":"你冷靜點，她目前沒事，我將她安置在安全的地方。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"마저 말해도 될까? 내가 말 끊기는 걸 조금 싫어해서…… 너도 알지?","JPN":"話を続けてもいいかしら？　私、言葉を切られるのはあまり好きじゃなくて……あなたも知ってるでしょう？","ENG":"May I continue? I don’t like being cut off... But you know that, don’t you?","TWN":"我可以繼續嗎？我不太喜歡被人打斷話……你也知道吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"마, 마, 말씀하세요…….","JPN":"つ、つ、続けてください……","ENG":"P-please, continue...","TWN":"是…是，您請說……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그 아이가 다녀갔던 곳들과 시기를 좀 조사해 봤어.","JPN":"あの子が出現した場所と時期をちょっと調べてみたの。","ENG":"I looked into where and when the child went.","TWN":"我有稍微調查過那孩子出現的地方和時間點。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아무래도 이상하잖아? <color=#ffd34c>헤이븐 랜드</color>며 <color=#ffd34c>위저드</color>며 활개치고 돌아다녔는데, 도둑맞은 것도 없고 누가 죽어나간 일도 없으니까.","JPN":"どう考えても変でしょう？　<color=#ffd34c>ヘイブンランド</color>であれ<color=#ffd34c>ウィザード</color>であれ、大手を振って行き来していたのに、盗まれたものもないし誰かが死んだこともないのよ。","ENG":"Isn’t it strange? She was all over <color=#ffd34c>Havenland</color> and <color=#ffd34c>Wizard</color>, but nothing was stolen and no one was injured.","TWN":"不覺得很奇怪嗎？這樣大搖大擺地闖進<color=#ffd34c>天堂樂園</color>或<color=#ffd34c>魔法師</color>，卻沒有任何東西失竊，或是人員死亡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래서 서류를 좀 살펴보니…… 후후. 그 아이가 다녀간 시점에 매출이 급증했더구나.","JPN":"それで書類を見てみたら……ふふ。あの子が出現したその時点で売り上げが急増していたの。","ENG":"So I looked at some other documents... Hu hu... It showed that after her sudden appearance, our revenue skyrocketed.","TWN":"於是我就查看一下資料，發現……呵呵，那孩子出現的時間，營收都會增加。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"매출이요?","JPN":"売り上げ？","ENG":"Revenue?","TWN":"營收？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래! 그것도 아주 높은 폭으로!","JPN":"そうよ！　しかもものすごい幅で！","ENG":"Yes! It was like nothing I’ve ever seen!","TWN":"沒錯！而且是激增！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"대체 무슨 일일까, 요정이 다녀간 것도 아닐 텐데 이게 무슨 조화일까. 아무리 고민을 해도 답을 찾을 수가 없었거든.","JPN":"これはいったいどういうことなのか、妖精の技でもなし、何が起こっているのか。いくら考えても答えが出なかったわ。","ENG":"I looked everywhere for the solution, but I couldn't find it. How was this even possible? It's not like a fairy appeared and saved the day, is it?","TWN":"這到底是怎麼回事呢？又不是有小精靈造訪，這是什麼樣的巧合？不管我怎麼想就是想不透。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그때 네가 그 아이와 같이 도망을 치고, 일을 시작했지. 악몽을 꾸지 않게 해주는 일을.","JPN":"その時、あなたがあの子と一緒に逃げ出して、仕事を始めたの。悪夢を見ないようにしてくれる仕事をね。","ENG":"But that’s when you and she ran away and started a business. Your business of getting rid of nightmares, that is.","TWN":"你和她逃跑後，不是開始做生意嗎？就是消除惡夢的生意？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"덕분에 명확하게 알 수 있었어. 악몽을 없애주는 능력이라면 헤이븐 랜드에 엄청난 이익을 가져다줄 거야.","JPN":"おかげではっきりとわかったのよ。悪夢を消してくれる能力なら、ヘイブンランドにとてつもない利益をもたらしてくれる。","ENG":"Thanks to you, it is now abundantly clear that Havenland will profit greatly from her ability to eliminate nightmares.","TWN":"我才終於想通，消除惡夢的能力，能夠為天堂樂園帶來巨大的利益。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"모두 즐겁고 행복하게 도박과 투기, 노름, 그 외 인간이 누릴 수 있는 모든 쾌락을 즐기고 우리 리조트에서 잠을 자겠지?","JPN":"みんな楽しく幸せにギャンブルと投機、賭け、その他人間が享受できるすべての快楽を楽しんで、私たちのリゾートに宿泊するでしょうね？","ENG":"Think about it. Everyone visits this location to gamble, enjoy themselves, feel joyous, and partake in other pleasures. But won't they come to our resort to sleep after that?","TWN":"大家在樂園裡不管是賭錢，還是其他的享樂之後，都會睡在度假村裡對吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이때, 그 애가 능력을 써서 악몽을 없애 줄 거야.","JPN":"その時、あの子が能力を使って悪夢を消してあげるの。","ENG":"Right then, we’ll use her ability to get rid of their nightmares.","TWN":"這個時候，再利用她的能力消除客人的惡夢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"사람들은 돈을 잃어버린 고통은 잊은 채, 결국 다시 헤이븐 랜드로 돌아 오겠지.","JPN":"みんなお金を失った苦しみを忘れて、結局またヘイブンランドに戻ってくるわ。","ENG":"Once they have forgotten the pain of losing their money, they will return to Havenland and repeat the process.","TWN":"那客人就會忘記輸錢的痛苦，再次回到天堂樂園來消費對吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"피폐해져서 더 빨아 먹을 것 없는 쓰레기가 될 뻔한 사람들을 의욕적으로 돈을 벌어와 탕진하는 훌륭한 고객으로 변화시켜 주는 거야.","JPN":"疲弊して、もう絞り取る小銭もないクズになるところだった人々を、頑張ってまたお金を稼いできては全財産を使い果たす、立派なお客様に変えてくれるの。","ENG":"We’ll turn those degenerates into devoted clients who strive to give us all of their hard-earned cash!","TWN":"也就是將那些被吃乾抹淨的垃圾，轉換成努力賺錢揮霍的好客人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"굉장히…… 이상적인 장소가 되는 거지. 우리 헤이븐 랜드가.","JPN":"とても……理想的な場所になるのよ。私たちのヘイブンランドが。","ENG":"Thus, Havenland will become... the ideal location.","TWN":"那我們的樂園……就會變成很棒的地方！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하지만…… 루루가 그렇게 많은 사람에게 능력을 쓸 수는 없어요…….","JPN":"でも……ルルはそんなにたくさんの人には能力を使えませんよ……","ENG":"But... Lulu can’t use her abilities on that many people...","TWN":"可是……露露無法對那麼多人使用能力……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저런. 글린다. 미리부터 포기하는 습관은 좋지 않아.","JPN":"あら。グリンダ。最初から諦める癖はよくないわ。","ENG":"Oh, Glinda. Giving up without even trying is a nasty habit.","TWN":"哎呀，格琳達，我不太喜歡先把話說死。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그 아이에게도 분명 잠재력이 있을 거다. 네가 그러했듯이.","JPN":"あの子にもきっと潜在力があるはずよ。あなたがそうだったようにね。","ENG":"I believe she has potential. Much like you did too.","TWN":"我相信她是有潛力的，就跟你一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제대로 써먹을 수나 있을까 싶던 너도 이렇게 엄청난 일을 해 왔잖니?","JPN":"ちゃんと使えるかどうかわからなかったあなたも、こんなに素晴らしいことを成し遂げたじゃない。","ENG":"Although people doubted your abilities, you nonetheless performed miracles, didn't you?","TWN":"你也曾經不被看好，但你不也表現得很出色嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그… 그럼…… 벌은 안 주시는 건가요?","JPN":"じゃ……じゃあ……お仕置きはないんですか？","ENG":"Th-then... You’re not going to p-punish me?","TWN":"所以…您……沒有要懲罰我嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼. 당연하지. 단, 부탁 하나만 들어준다면.","JPN":"ええ。もちろん。ただし、お願いを一つ聞いてくれたらね。","ENG":"Of course I won’t. But only if you do me this one favor...","TWN":"當然不會懲罰你，只是想拜託你一件事而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤론 님이…… 부탁을요?","JPN":"ヘロン様が……お願いを？","ENG":"A-a favor? M-madam Heron?","TWN":"海倫夫人……要拜託我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"너밖에 할 수 없는 일이란다.","JPN":"あなたにしかできないことよ。","ENG":"I can only entrust it to you.","TWN":"這件事唯有你做得到。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"루루라고 했던가? 그 애가 널 많이 찾아.","JPN":"ルルといったかしら？　あの子があなたを探しているわ。","ENG":"Lulu, was it? She’s been asking where you are.","TWN":"她是叫露露嗎？她一直要找你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루가요……?","JPN":"ルルがですか……？","ENG":"Lulu...?","TWN":"露露嗎……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"응. 네 말이 아니면 듣지 않겠다고 고집을 피우더라고.","JPN":"ええ。あなたの言うことじゃないと聞かないって意地を張ってね。","ENG":"Yes. She said she won’t do anything unless you told her to.","TWN":"對，她說她只聽你的話。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그 애가 말을 잘 들어야 헤이븐 님께서도 그 애를 괴롭히지 않으실 텐데…….","JPN":"あの子が言うことをよく聞けば、ヘイブン様も苦しめたりされないはずだけれど……","ENG":"Now, I just hope she’ll be a good girl if she doesn’t want Mr. Haven to lay his hands on her…","TWN":"她要聽話，天堂先生才不會找她麻煩……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아! 여기서 이러지 말고 일단 그 애를 보러 가지 않을래?","JPN":"あ！　ここでこうしてるのも何だし、とりあえずあの子に会いに行きましょうか？","ENG":"Oh, right! What are we doing this in here for? Shall we go see her?","TWN":"這樣吧！我們別光是待在這裡，不如先去看看她吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"널 애타게 기다리고 있을 거야.","JPN":"あなたを待ち焦がれているはずよ。","ENG":"She’s been waiting for you forever...","TWN":"她應該很著急要見你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네, 보러 갈래요……!","JPN":"はい、会いに行きます……！","ENG":"Yes, I want to see her...!","TWN":"好，我們去看她吧……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"감옥……? 루루가 여기에 있어요?","JPN":"牢獄……？　ここにルルがいるんですか？","ENG":"The jail cell...? This is where Lulu is?","TWN":"監獄……？露露被關在這裡嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어떻게 또 빠져나갈지 몰라서 어쩔 수 없었어.","JPN":"またどうやって逃げるかわからないから、仕方なかったのよ。","ENG":"Well... We had no choice. God forbid if she ever escapes again...","TWN":"我們也是逼不得已的，怕她又逃出去。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아. 저기 있네.","JPN":"ほら。あそこにいるわ。","ENG":"Oh, there she is.","TWN":"她在那。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어두워서 잘 안 보이는데…….","JPN":"暗くてよく見えないんですけど……","ENG":"It’s too dark. I can’t see...","TWN":"好暗喔，都看不清楚……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……루루? 루루 너 왜 이래!","JPN":"……ルル？　ルル、アンタどうしたの！？","ENG":"Lulu? Lulu?! Who did this to you?!","TWN":"……露露？你怎麼會這樣？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이건…… 피? 온몸이 피투성이…… 루루!!!","JPN":"これは……血？　全身血まみれ……ルル！！","ENG":"Is this... blood? She’s covered in blood...! Lulu!!!","TWN":"這是……血？渾身都是血……露露！！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}}]`);export{e as default};